 318→/// Generate Vitest test source from a behavior map.
 319→///
 320→/// Similar to Jest but uses `import { describe, it, expect } from 'vitest'`
 321→/// and imports the function from the module path.
 322→pub fn generate_vitest_tests(
 323→    behavior_map: &BehaviorMap,
 324→    function_name: &str,
 325→    module_path: &str,
 326→) -> String {
 327→    let mut out = String::new();
 328→
 329→    out.push_str("import { describe, it, expect } from 'vitest';\n");
 330→    out.push_str(&format!(
 331→        "import {{ {function_name} }} from '{module_path}';\n\n"
 332→    ));
 333→
 334→    out.push_str(&format!("describe('{function_name}', () => {{\n"));
 335→
 336→    if behavior_map.behaviors.is_empty() {
 337→        out.push_str("  // No behaviors observed\n");
 338→    }
 339→
 340→    for behavior in &behavior_map.behaviors {
 341→        let test_name = build_test_name(behavior);
 342→        let body = build_test_body(function_name, behavior);
 343→
 344→        out.push_str(&format!("  it('{test_name}', () => {{\n"));
 345→        out.push_str(&body);
 346→        out.push_str("  });\n\n");
 347→    }
 348→
 349→    out.push_str("});\n");
 350→    out
 351→}
 352→
 353→/// Build a descriptive test name from a behavior.
 354→fn build_test_name(behavior: &Behavior) -> String {
 355→    let inputs = format_args_short(&behavior.input_args);
 356→
 357→    if let Some(ref error) = behavior.thrown_error {
 358→        return format!(
 359→            "throws {} for input ({})",
 360→            escape_single_quotes(&error.message),
 361→            inputs
 362→        );
 363→    }
 364→
 365→    match &behavior.return_value {
 366→        Some(val) => format!(
 367→            "returns {} for input ({})",
 368→            format_value_short(val),
 369→            inputs
 370→        ),
 371→        None => format!("returns undefined for input ({inputs})"),
 372→    }
 373→}
 374→
 375→/// Build the body of an `it` block.
 376→fn build_test_body(function_name: &str, behavior: &Behavior) -> String {
 377→    let args = behavior
 378→        .input_args
 379→        .iter()
 380→        .map(format_value)
 381→        .collect::<Vec<_>>()
 382→        .join(", ");
 383→
 384→    let mut body = String::new();
 385→
 386→    if behavior.thrown_error.is_some() {
 387→        body.push_str(&format!(
 388→            "    expect(() => {function_name}({args})).toThrow();\n"
 389→        ));
 390→    } else {
 391→        let expected = match &behavior.return_value {
 392→            Some(val) => format_value(val),
 393→            None => "undefined".to_string(),
 394→        };
 395→        body.push_str(&format!(
 396→            "    const result = {function_name}({args});\n"
 397→        ));
 398→        body.push_str(&format!("    expect(result).toEqual({expected});\n"));
 399→    }
 400→
 401→    body
 402→}
 403→
 404→/// Format a JSON value for embedding in JavaScript source.
 405→///
 406→/// Detects `__complex_type` tagged objects and emits constructor calls.
 407→fn format_value(value: &serde_json::Value) -> String {
 408→    if let Some(js) = try_format_complex_js(value) {
 409→        return js;
 410→    }
 411→    match value {
 412→        serde_json::Value::String(s) => format!("'{}'", escape_single_quotes(s)),
 413→        serde_json::Value::Null => "null".to_string(),
 414→        serde_json::Value::Bool(b) => b.to_string(),
 415→        serde_json::Value::Number(n) => n.to_string(),
 416→        // For arrays/objects, use JSON.stringify-compatible output
 417→        other => other.to_string(),
 418→    }
 419→}
 420→
 421→/// Try to format a `__complex_type` tagged JSON object as a JavaScript constructor.
 422→/// Returns `None` if the value is not a tagged complex type.
 423→fn try_format_complex_js(value: &serde_json::Value) -> Option<String> {
 424→    let obj = value.as_object()?;
 425→    let tag = obj.get("__complex_type")?.as_str()?;
 426→    match tag {
 427→        "date" | "date_time" => {
 428→            let v = obj.get("value")?;
 429→            Some(format!("new Date({})", v))
 430→        }
 431→        "duration" => {
 432→            let ms = obj.get("ms").or_else(|| obj.get("value"))?;
 433→            Some(format!("/* Duration */ {}", ms))
 434→        }
 435→        "reg_exp" => {
 436→            let source = obj.get("source")?.as_str()?;
 437→            let flags = obj.get("flags").and_then(|f| f.as_str()).unwrap_or("");
 438→            Some(format!("/{source}/{flags}"))
 439→        }
 440→        "big_int" => {
 441→            let v = obj.get("value")?.as_str()?;
 442→            Some(format!("BigInt('{v}')"))
 443→        }
 444→        "url" => {
 445→            let v = obj.get("value")?.as_str()?;
 446→            Some(format!("new URL('{}')", escape_single_quotes(v)))
 447→        }
 448→        "buffer" => {
 449→            let v = obj.get("value")?.as_str()?;
 450→            let enc = obj.get("encoding").and_then(|e| e.as_str()).unwrap_or("base64");
 451→            Some(format!("Buffer.from('{v}', '{enc}')"))
 452→        }
 453→        "error" => {
 454→            let class = obj.get("class").and_then(|c| c.as_str()).unwrap_or("Error");
 455→            let msg = obj.get("message").and_then(|m| m.as_str()).unwrap_or("");
 456→            Some(format!("new {class}('{}')", escape_single_quotes(msg)))
 457→        }
 458→        "uuid" | "path" | "email" | "mime_type" | "locale" | "sem_ver" => {
 459→            let v = obj.get("value")?.as_str()?;
 460→            Some(format!("'{}'", escape_single_quotes(v)))
 461→        }
 462→        "symbol" => {
 463→            let desc = obj.get("description").and_then(|d| d.as_str()).unwrap_or("");
 464→            Some(format!("Symbol('{}')", escape_single_quotes(desc)))
 465→        }
 466→        "option" => {
 467→            let present = obj.get("present")?.as_bool()?;
 468→            if present {
 469→                let inner = obj.get("value")?;
 470→                Some(format_value(inner))
 471→            } else {
 472→                Some("undefined".to_string())
 473→            }
 474→        }
 475→        _ => None, // fall through to default JSON formatting
 476→    }
 477→}
 478→
 479→/// Shortened value for test names.
 480→fn format_value_short(value: &serde_json::Value) -> String {
 481→    let s = format_value(value);
 482→    if s.len() > 30 {
 483→        format!("{}...", &s[..27])
 484→    } else {
 485→        s
 486→    }
 487→}
 488→
 489→/// Shortened args list for test names.
 490→fn format_args_short(args: &[serde_json::Value]) -> String {
 491→    let parts: Vec<String> = args.iter().map(format_value_short).collect();
 492→    let joined = parts.join(", ");
 493→    if joined.len() > 50 {
 494→        format!("{}...", &joined[..47])
 495→    } else {
 496→        joined
 497→    }
 498→}
 499→
 500→/// Escape single quotes for JavaScript string literals.
 501→fn escape_single_quotes(s: &str) -> String {
 502→    s.replace('\'', "\\'")
 503→}
