 505→#[cfg(test)]
 506→mod tests {
 507→    use super::*;
 508→    use crate::behavior::{Behavior, BehaviorMap};
 509→    use crate::execution_record::ErrorInfo;
 510→    use serde_json::json;
 511→
 512→    fn make_behavior(
 513→        id: u32,
 514→        inputs: Vec<serde_json::Value>,
 515→        return_value: Option<serde_json::Value>,
 516→        error: Option<ErrorInfo>,
 517→    ) -> Behavior {
 518→        Behavior {
 519→            id,
 520→            input_args: inputs,
 521→            return_value,
 522→            thrown_error: error,
 523→            branch_path: vec![],
 524→            side_effects: vec![],
 525→            dependency_trace: None,
 526→        }
 527→    }
 528→
 529→    #[test]
 530→    fn generates_import_statement() {
 531→        let map = BehaviorMap {
 532→            function_id: "add".to_string(),
 533→            behaviors: vec![],
 534→            fingerprint: None,
 535→            nondeterministic_fields: vec![],
 536→        };
 537→        let output = generate_jest_tests(&map, "add", "./src/math");
 538→        assert!(output.starts_with("import { add } from './src/math';\n"));
 539→    }
 540→
 541→    #[test]
 542→    fn generates_describe_block() {
 543→        let map = BehaviorMap {
 544→            function_id: "add".to_string(),
 545→            behaviors: vec![],
 546→            fingerprint: None,
 547→            nondeterministic_fields: vec![],
 548→        };
 549→        let output = generate_jest_tests(&map, "add", "./src/math");
 550→        assert!(output.contains("describe('add', () => {"));
 551→        assert!(output.ends_with("});\n"));
 552→    }
 553→
 554→    #[test]
 555→    fn generates_it_block_for_return_value() {
 556→        let map = BehaviorMap {
 557→            function_id: "add".to_string(),
 558→            behaviors: vec![make_behavior(0, vec![json!(1), json!(2)], Some(json!(3)), None)],
 559→            fingerprint: None,
 560→            nondeterministic_fields: vec![],
 561→        };
 562→        let output = generate_jest_tests(&map, "add", "./src/math");
 563→
 564→        assert!(output.contains("it('returns 3 for input (1, 2)'"), "output: {output}");
 565→        assert!(output.contains("const result = add(1, 2);"));
 566→        assert!(output.contains("expect(result).toEqual(3);"));
 567→    }
 568→
 569→    #[test]
 570→    fn generates_it_block_for_string_return() {
 571→        let map = BehaviorMap {
 572→            function_id: "classify".to_string(),
 573→            behaviors: vec![make_behavior(
 574→                0,
 575→                vec![json!(5)],
 576→                Some(json!("positive")),
 577→                None,
 578→            )],
 579→            fingerprint: None,
