326→/// Compare two snapshots and produce a diff.
327→///
328→/// Behaviors are matched by function ID and behavior ID. For behaviors with the
329→/// same ID, the output/error is compared. Behaviors present only in one snapshot
330→/// are reported as new or removed.
331→pub fn diff(previous: &Snapshot, current: &Snapshot) -> SnapshotDiff {
332→    let mut entries = Vec::new();
333→
334→    // Index previous snapshot by (function_id, behavior_id)
335→    let mut prev_map: HashMap<(&str, &str), &SnapshotBehavior> = HashMap::new();
336→    let mut prev_functions: HashMap<&str, &FunctionSnapshot> = HashMap::new();
337→    for func in &previous.functions {
338→        prev_functions.insert(&func.function_id, func);
339→        for behavior in &func.behaviors {
340→            prev_map.insert((&func.function_id, &behavior.id), behavior);
341→        }
342→    }
343→
344→    // Walk current snapshot
345→    let mut seen_keys: std::collections::HashSet<(&str, &str)> =
346→        std::collections::HashSet::new();
347→
348→    for func in &current.functions {
349→        for behavior in &func.behaviors {
350→            let key = (func.function_id.as_str(), behavior.id.as_str());
351→            seen_keys.insert(key);
352→
353→            match prev_map.get(&key) {
354→                Some(prev_behavior) => {
355→                    let prev_outcome = BehaviorOutcome {
356→                        return_value: prev_behavior.expected_output.clone(),
357→                        error: prev_behavior.expected_error.clone(),
358→                    };
359→                    let curr_outcome = BehaviorOutcome {
360→                        return_value: behavior.expected_output.clone(),
361→                        error: behavior.expected_error.clone(),
362→                    };
363→
364→                    if prev_outcome == curr_outcome {
365→                        entries.push(BehaviorDiffEntry::Match {
366→                            behavior_id: behavior.id.clone(),
367→                            function_id: func.function_id.clone(),
368→                        });
369→                    } else {
370→                        entries.push(BehaviorDiffEntry::Regression {
371→                            behavior_id: behavior.id.clone(),
372→                            function_id: func.function_id.clone(),
373→                            previous: prev_outcome,
374→                            current: curr_outcome,
375→                        });
376→                    }
377→                }
378→                None => {
379→                    entries.push(BehaviorDiffEntry::New {
380→                        behavior_id: behavior.id.clone(),
381→                        function_id: func.function_id.clone(),
382→                    });
383→                }
384→            }
385→        }
386→    }
387→
388→    // Find removed behaviors (in previous but not in current)
389→    for func in &previous.functions {
390→        for behavior in &func.behaviors {
391→            let key = (func.function_id.as_str(), behavior.id.as_str());
392→            if !seen_keys.contains(&key) {
393→                entries.push(BehaviorDiffEntry::Removed {
394→                    behavior_id: behavior.id.clone(),
395→                    function_id: func.function_id.clone(),
396→                });
397→            }
398→        }
399→    }

//! Specification-level diffing: compare two [`FunctionSpec`]s to detect
//! behavioral regressions, added/removed equivalence classes, and changed
//! pre/postconditions.
//!
//! The main entry point is [`diff_specs`], which produces a [`SpecDiff`].
//! Two formatters are provided: [`format_spec_diff_text`] for human-readable
//! output and [`format_spec_diff_json`] for machine-readable JSON.

use serde::{Deserialize, Serialize};

use crate::equivalence::Precondition;
use crate::nondeterminism::NondeterministicField;
use crate::spec::{FunctionSpec, Postcondition, SpecClass};

/// The result of diffing two function specifications.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct SpecDiff {
    /// Function name being compared.
    pub function_name: String,
    /// Equivalence classes present in the new spec but not the old.
    pub added_classes: Vec<SpecClass>,
    /// Equivalence classes present in the old spec but not the new.
    pub removed_classes: Vec<SpecClass>,
    /// Postconditions that changed between matching classes.
    pub changed_postconditions: Vec<PostconditionChange>,
    /// Preconditions that changed between matching classes.
    pub changed_preconditions: Vec<PreconditionChange>,
    /// Invariant properties that held in the old spec but not the new.
    pub lost_properties: Vec<String>,
}

/// A postcondition that changed between two versions of a spec class.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct PostconditionChange {
    /// Label of the class where the change occurred.
    pub class_label: String,
    /// The old postcondition.
    pub old: Postcondition,
    /// The new postcondition.
    pub new: Postcondition,
}

/// A precondition change between two versions of a spec class.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct PreconditionChange {
    /// Label of the class where the change occurred.
    pub class_label: String,
    /// Preconditions that were removed (no longer hold).
    pub removed: Vec<Precondition>,
    /// Preconditions that were added (newly derived).
    pub added: Vec<Precondition>,
}

impl SpecDiff {
    /// Whether the diff is empty (specs are equivalent).
    pub fn is_empty(&self) -> bool {
        self.added_classes.is_empty()
            && self.removed_classes.is_empty()
            && self.changed_postconditions.is_empty()
            && self.changed_preconditions.is_empty()
            && self.lost_properties.is_empty()
    }

    /// Whether the diff contains regressions (removed classes, changed
    /// postconditions, or lost properties).
    pub fn has_regressions(&self) -> bool {
        !self.removed_classes.is_empty()
            || !self.changed_postconditions.is_empty()
            || !self.lost_properties.is_empty()
    }
}

/// Compare two function specs and produce a diff.
///
/// Classes are matched by their branch path. Classes with the same branch
/// path are compared for precondition and postcondition changes. Classes
/// that exist only in one spec are reported as added or removed.
pub fn diff_specs(old: &FunctionSpec, new: &FunctionSpec) -> SpecDiff {
    let mut added_classes = Vec::new();
    let mut removed_classes = Vec::new();
    let mut changed_postconditions = Vec::new();
    let mut changed_preconditions = Vec::new();
    let mut lost_properties = Vec::new();

    // Collect nondeterministic fields from both specs (union).
    let nondet_fields: Vec<&NondeterministicField> = old
        .nondeterministic_fields
        .iter()
        .chain(new.nondeterministic_fields.iter())
        .collect();

    // Index old classes by branch path for matching.
    let old_by_path: std::collections::HashMap<_, _> = old
        .classes
        .iter()
        .map(|c| (&c.branch_path, c))
        .collect();

    let new_by_path: std::collections::HashMap<_, _> = new
        .classes

//! Per-function fingerprinting for staleness detection.
//!
//! A fingerprint is a stable SHA-256 hash of a function's source text,
//! parameter types, and branch structure. When a fingerprint matches a
//! previously cached value, the function is unchanged and can be skipped
//! during re-exploration.

use std::collections::{HashMap, HashSet};
use std::fmt::Write as _;
use std::path::Path;

use sha2::{Digest, Sha256};

use crate::protocol::FunctionAnalysis;

/// Compute a hex-encoded SHA-256 fingerprint for a function.
///
/// The fingerprint incorporates:
/// - The function's source text (verbatim, including whitespace)
/// - Parameter names and types (sorted by name for stability)
/// - Branch structure: IDs, lines, condition text, types (sorted by ID)
///
/// Any change to these inputs produces a different fingerprint.
pub fn compute_function_fingerprint(source_text: &str, analysis: &FunctionAnalysis) -> String {
    let mut hasher = Sha256::new();

    // Hash source text.
    hasher.update(b"source:");
    hasher.update(source_text.as_bytes());

    // Hash parameters (sorted by name for determinism).
    let mut params: Vec<_> = analysis
        .params
        .iter()
        .map(|p| {
            let mut s = String::new();
            let _ = write!(s, "{}:{:?}", p.name, p.typ);
            if let Some(ref tn) = p.type_name {
                let _ = write!(s, "/{tn}");
            }
            s
        })
        .collect();
    params.sort();

    hasher.update(b"params:");
    for p in &params {
        hasher.update(p.as_bytes());
        hasher.update(b"\n");
    }

    // Hash branch structure (sorted by branch ID for determinism).
    let mut branches: Vec<_> = analysis
        .branches
        .iter()
        .map(|b| {
            let mut s = String::new();
            let _ = write!(s, "{}:{}:{:?}:{}", b.id, b.line, b.branch_type, b.condition_text);
            s
        })
        .collect();
    branches.sort();

    hasher.update(b"branches:");
    for b in &branches {
        hasher.update(b.as_bytes());
        hasher.update(b"\n");
    }

    format!("{:x}", hasher.finalize())
}

/// Compute a deep fingerprint that incorporates callee fingerprints.
///
/// Extends the shallow fingerprint by hashing in the deep fingerprints of all
/// in-scope callees (sorted by name for determinism). Callees not present in
/// `callee_deep_fingerprints` are ignored (they are out-of-scope and assumed stable).
///
/// Because scans process functions leaves-first, callee deep fingerprints are
/// always available before the caller is processed.
pub fn compute_deep_fingerprint(
    shallow_fingerprint: &str,
    callee_deep_fingerprints: &HashMap<String, String>,
    callees: &HashSet<String>,
) -> String {
    let mut hasher = Sha256::new();
    hasher.update(b"shallow:");
    hasher.update(shallow_fingerprint.as_bytes());

    let mut callee_fps: Vec<(&str, &str)> = callees
        .iter()
        .filter_map(|c| {
            callee_deep_fingerprints
                .get(c)
                .map(|fp| (c.as_str(), fp.as_str()))
        })
        .collect();
    callee_fps.sort_by_key(|(name, _)| *name);

    hasher.update(b"callees:");

